SELECT ?role ?roleLabel WHERE {
  wd:Q261759 p:P161 ?statement.
  ?statement pq:P453 ?role.
  ?role rdfs:label ?roleLabel.
  FILTER (LANG(?roleLabel) = 'en')
}

SELECT ?actor ?actorLabel WHERE {
  wd:Q261759 p:P161 ?statement.
  ?statement ps:P161 ?actor.
  ?actor rdfs:label ?actorLabel.
  FILTER (LANG(?actorLabel) = 'en' && ?actorLabel = 'Dakota Goyo')
}

SELECT ?actor ?actorLabel WHERE {
  wd:Q261759 p:P161 ?statement.
  ?statement ps:P161 ?actor.
  ?actor rdfs:label ?actorLabel.
  FILTER (LANG(?actorLabel) = 'en' && STR(?actorLabel) = 'Dakota Goyo')
}
